import React, { useState, useRef, useEffect } from 'react';

const FoodDetectionApp = () => {
  // 상태 관리
  const [currentMode, setCurrentMode] = useState('home');
  const [images, setImages] = useState([]);
  const [detectionResults, setDetectionResults] = useState({});
  const [ocrResults, setOcrResults] = useState({});
  const [geminiResults, setGeminiResults] = useState({});
  const [fridgeIngredients, setFridgeIngredients] = useState([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [confidence, setConfidence] = useState(0.5);
  const [statusMessage, setStatusMessage] = useState('해먹기 또는 사먹기를 선택하세요.');
  const [isDragOver, setIsDragOver] = useState(false);
  const [activeTab, setActiveTab] = useState('detection');
  const [showSaveButton, setShowSaveButton] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [userId, setUserId] = useState('user_' + Date.now());
  const [clearBeforeAnalysis, setClearBeforeAnalysis] = useState(false);
  const [selectedImageIndex, setSelectedImageIndex] = useState(0);
  const [processingImageIndex, setProcessingImageIndex] = useState(-1);
  
  // 직접 추가 기능 관련 상태
  const [showManualAdd, setShowManualAdd] = useState(false);
  const [manualIngredientName, setManualIngredientName] = useState('');
  const [manualIngredientQuantity, setManualIngredientQuantity] = useState(1);
  const [isAddingManual, setIsAddingManual] = useState(false);
  
  // Detection 결과 표시용 번역 캐시
  const [detectionTranslations, setDetectionTranslations] = useState({});

  // Detection 결과의 번역을 캐시하는 함수
  const getOrTranslateDetection = async (englishName) => {
    if (detectionTranslations[englishName]) {
      return detectionTranslations[englishName];
    }
    
    const translated = await translateDetectionResultWithGemini(englishName);
    setDetectionTranslations(prev => ({
      ...prev,
      [englishName]: translated
    }));
    
    return translated;
  };
  
  // Refs
  const fileInputRef = useRef(null);
  const analysisTimeoutRef = useRef(null);
  const manualInputRef = useRef(null);
  
  // API 설정
  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://192.168.0.19:8080';
  const GEMINI_API_KEY = process.env.REACT_APP_GEMINI_API_KEY || 'AIzaSyBBHRss0KLaEeeAgggsVOIGQ_zhS5ssDGw';
  const GEMINI_API_URL = process.env.REACT_APP_GEMINI_API_URL || 'https://generativelanguage.googleapis.com/v1/models/gemini-1.5-flash:generateContent';

  // 브랜드 패턴 데이터베이스 (gemini.py 기반 확장)
  const BRAND_PATTERNS = {
    '농심': ['신라면', '너구리', '안성탕면', '짜파게티', '육개장', '새우탕', '올리브'],
    '오뚜기': ['진라면', '스낵면', '컵누들', '참치마요', '카레', '3분카레'],
    '롯데': ['초코파이', '가나초콜릿', '빼빼로', '칸쵸', '몽쉘', '꼬깔콘'],
    '해태': ['홈런볼', '맛동산', '오예스', '허니버터칩', '신당동떡볶이'],
    '오리온': ['초코파이', '닥터유', '참붕어빵', '치토스'],
    '삼양': ['불닭볶음면', '까르보불닭', '삼양라면', '짜장불닭'],
    '팔도': ['팔도비빔면', '왕뚜껑'],
    '빙그레': ['바나나우유', '메로나', '투게더', '딸기우유'],
    '동원': ['참치캔', '김치찌개', '양반김', '리챔'],
    'CJ': ['햇반', '비비고', '백설'],
    '매일': ['매일우유', '상하목장'],
    '서울우유': ['서울우유', '아이셔'],
    '코카콜라': ['코카콜라', '스프라이트', '환타'],
    '펩시': ['펩시콜라', '마운틴듀'],
    '롯데칠성': ['칠성사이다', '델몬트', '펩시'],
    '동서식품': ['맥심', '포스트'],
    '네슬레': ['네스카페', '킷캣'],
    '크라운': ['산도', '쿠크다스'],
    '동양제과': ['초코하임', '요하임'],
    '광동': ['비타500', '홍삼정']
  };

  // OCR 텍스트 전처리 함수 (gemini.py 기반)
  const preprocessTextForBrandDetection = (text) => {
    if (!text) return "";
    
    // 불필요한 문자 제거 및 정규화
    text = text.replace(/[^\w\s가-힣]/g, ' ');
    text = text.replace(/\s+/g, ' ').trim();
    
    return text;
  };

  // 직접 브랜드/제품명 탐지 함수 (gemini.py 기반)
  const detectBrandAndProductDirect = (text) => {
    if (!text) return { brand: null, product: null, confidence: 0 };
    
    const preprocessed = preprocessTextForBrandDetection(text);
    const textUpper = preprocessed.toUpperCase();
    
    let detectedBrand = null;
    let detectedProduct = null;
    let maxConfidence = 0;
    
    // 브랜드별 제품 탐지
    Object.entries(BRAND_PATTERNS).forEach(([brand, products]) => {
      const brandUpper = brand.toUpperCase();
      const hasBrand = preprocessed.includes(brand) || textUpper.includes(brandUpper);
      
      products.forEach(product => {
        const productUpper = product.toUpperCase();
        const hasProduct = preprocessed.includes(product) || textUpper.includes(productUpper);
        
        if (hasProduct) {
          let confidence = product.length;
          if (hasBrand) {
            confidence += brand.length + 10; // 브랜드와 제품이 모두 있으면 높은 점수
          }
          
          if (confidence > maxConfidence) {
            detectedBrand = brand;
            detectedProduct = product;
            maxConfidence = confidence;
          }
        }
      });
    });
    
    // 브랜드 없이 제품명만 발견된 경우
    if (!detectedBrand) {
      Object.entries(BRAND_PATTERNS).forEach(([brand, products]) => {
        products.forEach(product => {
          const productUpper = product.toUpperCase();
          if (preprocessed.includes(product) || textUpper.includes(productUpper)) {
            const confidence = product.length;
            if (confidence > maxConfidence) {
              detectedBrand = brand;
              detectedProduct = product;
              maxConfidence = confidence;
            }
          }
        });
      });
    }
    
    return {
      brand: detectedBrand,
      product: detectedProduct,
      confidence: maxConfidence,
      fullName: detectedBrand && detectedProduct ? `${detectedBrand} ${detectedProduct}` : null
    };
  };

  // 식재료 관련 영어 단어들 (detection 결과 번역용)
  const FOOD_INGREDIENTS = {
    'apple': '사과',
    'banana': '바나나', 
    'carrot': '당근',
    'tomato': '토마토',
    'orange': '오렌지',
    'onion': '양파',
    'potato': '감자',
    'cucumber': '오이',
    'lettuce': '상추',
    'broccoli': '브로콜리',
    'cabbage': '양배추',
    'eggs': '계란',
    'egg': '계란',
    'milk': '우유',
    'bread': '빵',
    'rice': '쌀',
    'chicken': '닭고기',
    'beef': '소고기',
    'pork': '돼지고기',
    'fish': '생선',
    'blueberry': '블루베리',
    'strawberry': '딸기',
    'eggplant': '가지',
    'zucchini': '호박',
    'bell pepper': '피망',
    'cauliflower': '콜리플라워',
    'spinach': '시금치',
    'shrimp': '새우',
    'corn': '옥수수',
    'cheese': '치즈',
    'yogurt': '요거트',
    'butter': '버터',
    'flour': '밀가루',
    'sugar': '설탕',
    'salt': '소금',
    'mushroom': '버섯',
    'garlic': '마늘',
    'ginger': '생강',
    'lemon': '레몬',
    'lime': '라임',
    'grape': '포도',
    'watermelon': '수박',
    'pineapple': '파인애플',
    'avocado': '아보카도',
    'radish': '무',
    'pepper': '고추',
    'bean': '콩',
    'celery': '셀러리',
    'asparagus': '아스파라거스',
    'kale': '케일',
    'sweet potato': '고구마',
    'pumpkin': '호박'
  };

  // 아이콘 컴포넌트들
  const CookingIcon = () => <span className="text-2xl md:text-3xl">👨‍🍳</span>;
  const EatingIcon = () => <span className="text-2xl md:text-3xl">🍽️</span>;
  const UploadIcon = () => <span className="text-sm">📁</span>;
  const EyeIcon = () => <span className="text-sm">👁️</span>;
  const BrainIcon = () => <span className="text-sm">🧠</span>;
  const FileTextIcon = () => <span className="text-sm">📄</span>;
  const FridgeIcon = () => <span className="text-lg md:text-xl">🧊</span>;
  const BackIcon = () => <span className="text-sm">←</span>;
  const PlusIcon = () => <span className="text-sm">+</span>;
  const MinusIcon = () => <span className="text-sm">-</span>;
  const DeleteIcon = () => <span className="text-sm">🗑️</span>;
  const SaveIcon = () => <span className="text-sm">💾</span>;
  const CheckIcon = () => <span className="text-sm">✅</span>;
  const CloseIcon = () => <span className="text-sm">✕</span>;
  const EditIcon = () => <span className="text-sm">✏️</span>;
  const AllIcon = () => <span className="text-sm">🔄</span>;
  const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
  );

  // useEffect hooks
  useEffect(() => {
    return () => {
      if (analysisTimeoutRef.current) {
        clearTimeout(analysisTimeoutRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (showManualAdd && manualInputRef.current) {
      manualInputRef.current.focus();
    }
  }, [showManualAdd]);

  // 브랜드 탐지 함수 (기존 코드 업데이트)
  const detectBrandAndProduct = (text) => {
    return detectBrandAndProductDirect(text);
  };

  // 식품명 추출 함수 (gemini.py 기반 개선)
  const extractFoodNameWithBrands = (geminiResult, detectedBrand) => {
    if (!geminiResult) {
      // Gemini 결과가 없으면 직접 탐지된 결과 사용
      if (detectedBrand?.fullName) {
        return detectedBrand.fullName;
      }
      return null;
    }
    
    try {
      // 줄 단위로 분리해서 첫 번째 줄만 사용
      const lines = geminiResult.trim().split('\n');
      let firstLine = lines[0].trim();
      
      // 불필요한 접두사 제거
      const prefixes = [
        "추론된 식품:", "식품명:", "제품명:", "상품명:", "분석 결과:", 
        "결과:", "답변:", "식품:", "추론 결과:", "판단 결과:", "**", "*"
      ];
      
      for (const prefix of prefixes) {
        if (firstLine.startsWith(prefix)) {
          firstLine = firstLine.substring(prefix.length).trim();
        }
      }
      
      // 마크다운 굵은 글씨 제거
      firstLine = firstLine.replace(/\*\*/g, '').replace(/\*/g, '');
      
      // 괄호 안의 부가 설명 제거 (예: "신라면 (매운맛)" -> "신라면")
      if (firstLine.includes('(') && firstLine.includes(')')) {
        firstLine = firstLine.split('(')[0].trim();
      }
      
      // 직접 탐지된 브랜드/제품과 비교
      if (detectedBrand?.fullName) {
        const expectedName = detectedBrand.fullName;
        // Gemini 결과에 브랜드+제품명이 포함되어 있고 길이가 합리적이면 사용
        if (detectedBrand.brand && detectedBrand.product && 
            firstLine.includes(detectedBrand.brand) && firstLine.includes(detectedBrand.product)) {
          if (firstLine.length <= expectedName.length + 15) { // 너무 길지 않으면
            return firstLine;
          }
        }
        // 그렇지 않으면 직접 탐지된 결과 우선 사용
        return expectedName;
      }
      
      return firstLine || null;
      
    } catch (error) {
      console.error('❌ 식품명 추출 중 오류:', error);
      // 오류 시 직접 탐지된 결과 사용
      if (detectedBrand?.fullName) {
        return detectedBrand.fullName;
      }
      return geminiResult;
    }
  };

  // 개선된 Gemini API 호출 함수 (gemini.py 기반)
  const callGeminiAPIWithBrands = async (prompt, text, detectionResults = null) => {
    try {
      console.log(`🤖 Gemini 분석 시작 - 텍스트: "${text}"`);
      
      // 1단계: 직접 브랜드/제품명 탐지
      const brandDetection = detectBrandAndProductDirect(text);
      let brandContext = "";
      
      if (brandDetection?.fullName) {
        brandContext = `\n\n🏪 중요: 텍스트에서 '${brandDetection.fullName}' 브랜드/제품이 직접 탐지되었습니다. 이를 최우선으로 고려하세요.`;
        console.log(`🎯 직접 탐지된 브랜드/제품: ${brandDetection.fullName}`);
      } else if (brandDetection?.brand) {
        brandContext = `\n\n🏪 참고: 텍스트에서 '${brandDetection.brand}' 브랜드가 탐지되었습니다.`;
        console.log(`🎯 직접 탐지된 브랜드: ${brandDetection.brand}`);
      }
      
      let detectionContext = "";
      if (detectionResults && detectionResults.length > 0) {
        const detectedClasses = detectionResults.filter(det => det.class !== 'other').map(det => det.class);
        if (detectedClasses.length > 0) {
          detectionContext = `\n\n🎯 참고: 이미지에서 다음 식품들이 탐지되었습니다: ${detectedClasses.join(', ')}`;
        }
      }
      
      // gemini.py 스타일의 강화된 프롬프트
      const enhancedPrompt = `${prompt}${brandContext}${detectionContext}

🏪 주요 브랜드별 대표 제품들:
• 농심: 신라면, 너구리, 안성탕면, 짜파게티, 육개장
• 오뚜기: 진라면, 컵누들, 참치마요, 3분카레
• 롯데: 초코파이, 가나초콜릿, 빼빼로, 칸쵸
• 해태: 홈런볼, 맛동산, 허니버터칩
• 삼양: 불닭볶음면, 까르보불닭
• 빙그레: 바나나우유, 메로나, 딸기우유
• 동원: 참치캔, 양반김, 리챔
• CJ: 햇반, 비비고
• 광동: 비타500, 홍삼정

⚠️ 중요: 실제 유통 중인 브랜드+제품명 조합을 최우선으로 추론하세요!
브랜드명과 제품명이 모두 확인되면 반드시 그 조합을 사용하세요.`;
      
      const response = await fetch(`${GEMINI_API_URL}?key=${GEMINI_API_KEY}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          contents: [{
            parts: [{
              text: enhancedPrompt
            }]
          }],
          generationConfig: {
            temperature: 0.05,  // 더욱 일관된 결과
            topK: 20,
            topP: 0.7,
            maxOutputTokens: 200,
          }
        }),
      });

      if (response.ok) {
        const data = await response.json();
        const result = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
        console.log(`🤖 Gemini 원본 응답: "${result}"`);
        
        const finalResult = extractFoodNameWithBrands(result, brandDetection);
        console.log(`🎯 최종 추론 결과: "${finalResult}"`);
        return finalResult;
      } else {
        throw new Error(`Gemini API 오류: ${response.status}`);
      }
    } catch (error) {
      console.error('❌ Gemini API 호출 실패:', error);
      
      // API 실패 시 직접 탐지된 결과 반환
      const brandDetection = detectBrandAndProductDirect(text);
      if (brandDetection?.fullName) {
        console.log(`🔄 API 실패로 직접 탐지 결과 사용: ${brandDetection.fullName}`);
        return brandDetection.fullName;
      }
      
      throw error;
    }
  };

  // Gemini를 활용한 Detection 결과 번역 및 식재료 판별 함수
  const translateDetectionResultWithGemini = async (englishName) => {
    try {
      const prompt = `다음 영어 단어가 식재료/음식인지 판별하고, 맞다면 한국어로 번역해주세요.

영어 단어: "${englishName}"

🎯 판별 및 번역 규칙:
1. 식재료/음식이 맞는지 먼저 판별
2. 식재료/음식이면 정확한 한국어명으로 번역
3. 식재료/음식이 아니면 "NOT_FOOD" 반환

❌ 식재료/음식이 아닌 것들:
- 사람, 손, 몸의 일부 (person, hand, human)
- 포장재, 용기 (bottle, package, container, box, bag)
- 식기류 (plate, bowl, cup, glass, knife, fork, spoon)
- 가구, 건물 구조 (table, chair, wall, floor, window, door)
- 재질명 (plastic, metal, wood, paper, cloth, fabric)

✅ 식재료/음식인 것들:
- 과일, 채소, 육류, 생선, 유제품, 곡물 등

응답 형식:
- 식재료/음식인 경우: 한국어명만 (예: "사과", "당근", "닭고기")
- 식재료/음식이 아닌 경우: "NOT_FOOD"

응답:`;

      const response = await fetch(`${GEMINI_API_URL}?key=${GEMINI_API_KEY}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          contents: [{
            parts: [{
              text: prompt
            }]
          }],
          generationConfig: {
            temperature: 0.05,
            topK: 20,
            topP: 0.7,
            maxOutputTokens: 50,
          }
        }),
      });

      if (response.ok) {
        const data = await response.json();
        const result = data.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';
        
        // 결과 정리
        const cleanResult = result.replace(/[^\가-힣a-zA-Z_]/g, '').trim();
        
        if (cleanResult === 'NOT_FOOD' || cleanResult === 'NOTFOOD') {
          return null; // 식재료가 아님
        }
        
        if (cleanResult && cleanResult !== englishName && /[가-힣]/.test(cleanResult)) {
